from __future__ import annotations

from pathlib import Path

import baostock as bs
import pandas as pd


HISTORICAL_COLUMNS = ["date", "symbol", "name", "api_effective_date"]


def _normalize_symbol(symbol: str) -> str:
    return str(symbol).split(".")[-1].zfill(6)


def load_or_build_hs300_history(
    dates: pd.Series | list[pd.Timestamp],
    cache_path: Path,
    force_refresh: bool = False,
) -> pd.DataFrame:
    if cache_path.exists() and not force_refresh:
        df = pd.read_csv(cache_path, dtype={"symbol": str})
        df["date"] = pd.to_datetime(df["date"])
        df["api_effective_date"] = pd.to_datetime(df["api_effective_date"])
        return df.sort_values(["date", "symbol"]).reset_index(drop=True)

    query_dates = sorted(pd.to_datetime(pd.Index(dates)).unique())
    if not query_dates:
        raise RuntimeError("no dates supplied for historical universe reconstruction")

    lg = bs.login()
    if lg.error_code != "0":
        raise RuntimeError(f"baostock login failed: {lg.error_msg}")

    rows: list[dict] = []
    try:
        total = len(query_dates)
        for idx, date in enumerate(query_dates, start=1):
            rs = bs.query_hs300_stocks(date=date.strftime("%Y-%m-%d"))
            if rs.error_code != "0":
                raise RuntimeError(f"query_hs300_stocks failed for {date.date()}: {rs.error_msg}")
            fetched = 0
            while rs.next():
                effective_date, symbol, name = rs.get_row_data()
                rows.append(
                    {
                        "date": date,
                        "symbol": _normalize_symbol(symbol),
                        "name": name,
                        "api_effective_date": pd.Timestamp(effective_date),
                    }
                )
                fetched += 1
            if fetched == 0:
                raise RuntimeError(f"query_hs300_stocks returned no rows for {date.date()}")
            if idx % 50 == 0 or idx == total:
                print(f"[universe] reconstructed {idx}/{total} trade dates")
    finally:
        bs.logout()

    df = pd.DataFrame(rows, columns=HISTORICAL_COLUMNS).sort_values(["date", "symbol"]).reset_index(drop=True)
    cache_path.parent.mkdir(parents=True, exist_ok=True)
    df.to_csv(cache_path, index=False)
    return df


def build_union_universe(membership_df: pd.DataFrame) -> pd.DataFrame:
    latest = (
        membership_df.sort_values(["symbol", "date"])
        .groupby("symbol", as_index=False)
        .tail(1)[["symbol", "name"]]
        .sort_values("symbol")
        .reset_index(drop=True)
    )
    return latest.rename(columns={"symbol": "成分券代码", "name": "成分券名称"})


def summarize_historical_universe(membership_df: pd.DataFrame) -> dict:
    daily_counts = membership_df.groupby("date")["symbol"].nunique()
    effective_dates = membership_df[["date", "api_effective_date"]].drop_duplicates()
    return {
        "membership_rows": int(len(membership_df)),
        "unique_symbols": int(membership_df["symbol"].nunique()),
        "trade_dates": int(membership_df["date"].nunique()),
        "min_daily_count": int(daily_counts.min()),
        "max_daily_count": int(daily_counts.max()),
        "avg_daily_count": float(daily_counts.mean()),
        "first_date": str(membership_df["date"].min().date()),
        "last_date": str(membership_df["date"].max().date()),
        "api_effective_date_changes": int(effective_dates["api_effective_date"].nunique()),
    }

